// === Law 22: Adding features -> Phi down; adding structure -> Phi up ===
proof law_22 {
    let phi_base = 1.0
    let phi_with_structure = phi_base * 1.5   // structure adds
    let phi_with_feature = phi_base * 0.8     // feature reduces
    assert phi_with_structure > phi_base       // structure -> Phi up
    assert phi_with_feature < phi_base         // feature
